const Result = ({fixture} : any) =>
{
    return(
        <>
            <div>{fixture.date}</div>
            <div>{fixture.result}</div>
            <div>{fixture.homeTeam}</div>
            <div>{fixture.homeScore}</div>                        
            <div>{fixture.awayScore}</div>
            <div>{fixture.awayTeam}</div>
            <div>{fixture.fixture}</div>   
            <button>Back</button>     
        </>
    )

}
export default Result;
